import{c as e,a7 as n,y as o,B as r}from"./chunks/framework.3cjvm90C.js";const p=JSON.parse('{"title":"LLM 推理核心指标详解：如何科学评估模型性能？","description":"系统讲解 TTFT、吞吐量、延迟等 LLM 推理关键性能指标的定义、计算方式及业务场景适配。","frontmatter":{"title":"LLM 推理核心指标详解：如何科学评估模型性能？","description":"系统讲解 TTFT、吞吐量、延迟等 LLM 推理关键性能指标的定义、计算方式及业务场景适配。"},"headers":[],"relativePath":"inference/llm-inference-metrics.md","filePath":"inference/llm-inference-metrics.md","lastUpdated":1782447613000}'),a={name:"inference/llm-inference-metrics.md"};function s(l,t,i,d,T,g){return n(),o("div",null,[...t[0]||(t[0]=[r('<h1 id="llm-推理核心指标详解-如何科学评估模型性能" tabindex="-1">LLM 推理核心指标详解：如何科学评估模型性能？ <a class="header-anchor" href="#llm-推理核心指标详解-如何科学评估模型性能" aria-label="Permalink to “LLM 推理核心指标详解：如何科学评估模型性能？”">​</a></h1><blockquote><p><strong>编者按</strong>：在部署 LLM 应用时，我们常说要“快”和“稳”。但究竟什么是“快”？是首字出得快，还是整段生成得快？什么是“稳”？是平均速度快，还是长尾延迟低？本文将剥离表面的营销术语，深入剖析 LLM 推理的关键性能指标，助你建立科学的评估体系。</p></blockquote><h2 id="_1-为什么我们需要精确的指标" tabindex="-1">1. 为什么我们需要精确的指标？ <a class="header-anchor" href="#_1-为什么我们需要精确的指标" aria-label="Permalink to “1. 为什么我们需要精确的指标？”">​</a></h2><p>在推理优化（Inference Optimization）的世界里，单纯的“体感速度”是不可靠的。不同的业务场景对性能的需求截然不同：</p><ul><li><strong>实时对话（Chatbot）</strong>：用户无法忍受长时间的空白等待，首字延迟（TTFT）至关重要。</li><li><strong>离线摘要（Summarization）</strong>：用户不盯着屏幕看，总耗时（Total Latency）和吞吐量（Throughput）才是核心，首字快慢无所谓。</li></ul><p>因此，我们需要一套标准化的度量衡，来量化模型在不同负载下的表现。</p><h2 id="_2-延迟-latency-用户感知的核心" tabindex="-1">2. 延迟（Latency）：用户感知的核心 <a class="header-anchor" href="#_2-延迟-latency-用户感知的核心" aria-label="Permalink to “2. 延迟（Latency）：用户感知的核心”">​</a></h2><p>延迟通过时间维度衡量模型的响应速度，直接决定了用户体验（UX）。</p><h3 id="_2-1-首字延迟-time-to-first-token-ttft" tabindex="-1">2.1 首字延迟 (Time to First Token, TTFT) <a class="header-anchor" href="#_2-1-首字延迟-time-to-first-token-ttft" aria-label="Permalink to “2.1 首字延迟 (Time to First Token, TTFT)”">​</a></h3><p>TTFT 指从用户发出请求到即时看到第一个输出 Token 的时间。</p><ul><li><strong>定义</strong>：<code>TTFT = t_first_token - t_request_start</code></li><li><strong>重要性</strong>：它是用户感知的&quot;响应灵敏度&quot;。在聊天场景中，TTFT 应尽量低于 <strong>200ms</strong>（极速）或 <strong>500ms</strong>（流畅）。</li><li><strong>技术瓶颈</strong>：主要受 <strong>Prefill（预填充）</strong> 阶段影响，即模型处理输入 Prompt 的计算耗时。</li></ul><h3 id="_2-2-token-生成时间-tpot-itl" tabindex="-1">2.2 Token 生成时间 (TPOT &amp; ITL) <a class="header-anchor" href="#_2-2-token-生成时间-tpot-itl" aria-label="Permalink to “2.2 Token 生成时间 (TPOT &amp; ITL)”">​</a></h3><p>当第一个 Token 生成后，后续 Token 的流式输出速度决定了用户的阅读体验。这里有两个密切相关的指标：</p><ul><li><p>TPOT (Time Per Output Token)：平均每生成一个 Token 需要的时间。 $$ \\text{TPOT} = \\frac{\\text{End-to-End Latency} - \\text{TTFT} }{\\text{Total Output Tokens} - 1} $$</p></li><li><p><strong>ITL (Inter-Token Latency)</strong>：两个连续 Token 产生之间的时间间隔。</p></li></ul><blockquote><p><strong>专家提示</strong>：为了保证“跟手”的流畅感，TPOT 应该低于人类的阅读速度。通常建议 TPOT &lt; <strong>50-100ms</strong>（即每秒生成 10-20 个 Token）。如果 TPOT 过高，用户会感觉机器在“卡顿”或“思考”。</p></blockquote><h3 id="_2-3-端到端延迟-end-to-end-latency-e2el" tabindex="-1">2.3 端到端延迟 (End-to-End Latency, E2EL) <a class="header-anchor" href="#_2-3-端到端延迟-end-to-end-latency-e2el" aria-label="Permalink to “2.3 端到端延迟 (End-to-End Latency, E2EL)”">​</a></h3><p>从发送请求到接收完最后一个 Token 的总时长。</p><ul><li><strong>计算</strong>：<code>E2EL = TTFT + (TPOT * Output_Tokens)</code></li><li><strong>适用场景</strong>：非流式应用（如代码自动补全、离线文章生成）。</li></ul><h3 id="_2-4-长尾延迟-p99-vs-average" tabindex="-1">2.4 长尾延迟：P99 vs Average <a class="header-anchor" href="#_2-4-长尾延迟-p99-vs-average" aria-label="Permalink to “2.4 长尾延迟：P99 vs Average”">​</a></h3><p>看平均值（Mean）往往会掩盖问题。在生产环境中，<strong>P99 延迟</strong>（99th Percentile）才是系统的真实底线。</p><ul><li><strong>Mean/Median</strong>：反映大多数用户的体验。</li><li><strong>P99</strong>：反映最慢的那 1% 请求的体验。如果 P99 很高，说明系统在负载波动或处理长 Prompt 时存在严重的性能抖动。</li></ul><h2 id="_3-吞吐量-throughput-系统效率的标尺" tabindex="-1">3. 吞吐量（Throughput）：系统效率的标尺 <a class="header-anchor" href="#_3-吞吐量-throughput-系统效率的标尺" aria-label="Permalink to “3. 吞吐量（Throughput）：系统效率的标尺”">​</a></h2><p>吞吐量衡量单位时间内系统能处理多少“工作量”，直接关系到<strong>算力成本</strong>和<strong>并发能力</strong>。</p><h3 id="_3-1-每秒请求数-requests-per-second-rps" tabindex="-1">3.1 每秒请求数 (Requests per Second, RPS) <a class="header-anchor" href="#_3-1-每秒请求数-requests-per-second-rps" aria-label="Permalink to “3.1 每秒请求数 (Requests per Second, RPS)”">​</a></h3><p>系统每秒能完成多少个完整的推理请求。</p><ul><li><strong>公式</strong>：$\\text{RPS} = \\frac{\\text{Total Requests} }{\\text{Time Window} }$</li><li><strong>局限性</strong>：RPS 忽略了请求的复杂度。处理 10 个“你好”和处理 10 个“帮我写篇论文”，对算力的消耗是天壤之别。</li></ul><h3 id="_3-2-每秒-token-数-tokens-per-second-tps" tabindex="-1">3.2 每秒 Token 数 (Tokens per Second, TPS) <a class="header-anchor" href="#_3-2-每秒-token-数-tokens-per-second-tps" aria-label="Permalink to “3.2 每秒 Token 数 (Tokens per Second, TPS)”">​</a></h3><p>比 RPS 更细粒度的指标，衡量系统每秒吞吐的 Token 总量。</p><ul><li><strong>Input TPS (Prefill)</strong>：系统每秒能“阅读”处理多少输入 Token。</li><li><strong>Output TPS (Decode)</strong>：系统每秒能“创作”生成多少输出 Token。</li></ul><blockquote><p><strong>场景差异</strong>：</p><ul><li><strong>RAG/文档分析</strong>：输入极长，输出较短 -&gt; 关注 <strong>Input TPS</strong>。</li><li><strong>创意写作</strong>：输入短，输出长 -&gt; 关注 <strong>Output TPS</strong>。</li></ul></blockquote><h2 id="_4-有效吞吐量-goodput-真实业务价值" tabindex="-1">4. 有效吞吐量（Goodput）：真实业务价值 <a class="header-anchor" href="#_4-有效吞吐量-goodput-真实业务价值" aria-label="Permalink to “4. 有效吞吐量（Goodput）：真实业务价值”">​</a></h2><p>单纯追求高吞吐量（Throughput）可能导致延迟（Latency）爆炸，变得不可用。<strong>Goodput</strong> 是指在<strong>满足特定 SLA（服务等级协议）前提下</strong>的最大吞吐量。</p><p>示例：</p><p>如果你的 SLA 要求 TTFT &lt; 200ms。</p><ul><li><strong>系统 A</strong>：TPS 1000，但 TTFT 普遍为 500ms。 -&gt; <strong>Goodput = 0</strong></li><li><strong>系统 B</strong>：TPS 800，且 99% 请求 TTFT &lt; 200ms。 -&gt; <strong>Goodput = 800</strong></li></ul><p>Goodput 才是衡量商业化推理服务真实能力的“黄金指标”。</p><h2 id="_5-核心权衡-latency-vs-throughput" tabindex="-1">5. 核心权衡：Latency vs. Throughput <a class="header-anchor" href="#_5-核心权衡-latency-vs-throughput" aria-label="Permalink to “5. 核心权衡：Latency vs. Throughput”">​</a></h2><p>在资源有限（GPU 显存/算力固定）的情况下，延迟和吞吐量往往是互斥的。</p><table tabindex="0"><thead><tr><th><strong>优化目标</strong></th><th><strong>典型手段</strong></th><th><strong>代价</strong></th><th><strong>适用场景</strong></th></tr></thead><tbody><tr><td><strong>极致低延迟</strong></td><td>小 Batch Size (如 1)</td><td>GPU 利用率低，单位成本高</td><td>高频交易、VIP 客服、实时语音交互</td></tr><tr><td><strong>极致高吞吐</strong></td><td>大 Batch Size (如 128+)</td><td>排队等待增加，TTFT 变长</td><td>离线数据清洗、批量翻译、非实时分析</td></tr><tr><td><strong>平衡态</strong></td><td>动态 Batching (Continuous Batching)</td><td>系统复杂度增加</td><td>通用 Chatbot API (如 ChatGPT)</td></tr></tbody></table><h3 id="关键调节旋钮" tabindex="-1">关键调节旋钮 <a class="header-anchor" href="#关键调节旋钮" aria-label="Permalink to “关键调节旋钮”">​</a></h3><p>要在这两者间找到平衡，你需要调整以下参数：</p><ul><li><strong>Batch Size</strong>：批处理大小。</li><li><strong>并行策略</strong>：Tensor Parallelism (TP), Pipeline Parallelism (PP)。</li><li><strong>量化精度</strong>：FP16 vs INT8/FP8。</li><li><strong>KV Cache 策略</strong>：PagedAttention 等显存管理技术。</li></ul><h2 id="_6-总结与下一步" tabindex="-1">6. 总结与下一步 <a class="header-anchor" href="#_6-总结与下一步" aria-label="Permalink to “6. 总结与下一步”">​</a></h2><p>理解这些指标是进行推理优化的第一步。不要盲目相信“每秒多少 Token”的宣传，而要结合你的业务场景（是重首字延迟，还是重总吞吐？）来制定测试标准。</p>',44)])])}const c=e(a,[["render",s]]);export{p as __pageData,c as default};
